export async function POST(req: Request) {
  const session = await getServerSession(authOptions)
  if (!session || !(session.user as any).isAdmin) {
    return NextResponse.json({ error: 'Não autorizado' }, { status: 401 })
  }

  await ensureDatabaseSchema()

  const now = new Date().toISOString()
  const stats = { teams: 0, athletes: 0, coaches: 0, skipped: 0, errors: [] as string[] }

  // 1. Delete all existing athletes and coaches (test data)
  await prisma.athlete.deleteMany({})
  await prisma.$executeRawUnsafe('DELETE FROM "CoachStaff"')

  // 2. Upsert teams and build legacyId → uuid map
  const teamIdMap: Record<number, string> = {}
  for (const club of CLUBS_DATA) {
    try {
      const existing = await prisma.team.findFirst({ where: { name: club.name } })
      if (existing) {
        await prisma.$executeRawUnsafe(
          `UPDATE "Team" SET "cnpj"=?, "isActive"=1 WHERE "id"=?`,
          club.cnpj, existing.id
        )
        teamIdMap[club.legacyId] = existing.id
      } else {
        const id = randomUUID()
        await prisma.$executeRawUnsafe(
          `INSERT INTO "Team" ("id","name","cnpj","state","isActive","totalFeesOwed","createdAt","updatedAt") VALUES (?,?,?,'RS',1,0,?,?)`,
          id, club.name, club.cnpj, now, now
        )
        teamIdMap[club.legacyId] = id
      }
      stats.teams++
    } catch (e: any) {
      stats.errors.push(`Team ${club.name}: ${e.message}`)
    }
  }

  // 3. Build club name → teamId map for coaches (normalized)
  const clubNameToId = new Map<string, string>()
  for (const club of CLUBS_DATA) {
    if (teamIdMap[club.legacyId]) {
      const key = club.name.toLowerCase().replace(/\s+/g, ' ').trim()
      clubNameToId.set(key, teamIdMap[club.legacyId])
    }
  }
  function findTeamByClubName(clubName: string): string | null {
    const key = clubName.toLowerCase().replace(/\s+/g, ' ').trim()
    if (clubNameToId.has(key)) return clubNameToId.get(key)!
    for (const [name, id] of clubNameToId.entries()) {
      if (key.includes(name.substring(0, 10)) || name.includes(key.substring(0, 10))) return id
    }
    return null
  }

  // 4. Create athletes in batches of 50
  const athleteBatches: (typeof ATHLETES_DATA)[] = []
  for (let i = 0; i < ATHLETES_DATA.length; i += 50) {
    athleteBatches.push(ATHLETES_DATA.slice(i, i + 50))
  }
  for (const batch of athleteBatches) {
    await prisma.$transaction(
      batch.map(a => {
        const teamId = a.cl > 0 ? (teamIdMap[a.cl] ?? null) : null
        return prisma.athlete.create({
          data: {
            id: randomUUID(),
            name: a.n,
            teamId: teamId ?? undefined,
            registrationNumber: a.r,
            cpf: a.cpf || null,
            mobile: a.mob || null,
            birthDate: a.bd ? new Date(a.bd) : null,
            situation: a.sit,
            rg: a.rg || null,
            rgOrgan: a.rgo || null,
            rgDate: a.rgd ? new Date(a.rgd) : null,
            motherName: a.mom || null,
            fatherName: a.dad || null,
            sex: a.sex || null,
            cep: a.cep || null,
            city: a.cty || null,
            address: a.adr || null,
            addressNum: a.anum || null,
            addressComp: a.acomp || null,
            maritalStatus: a.ms || null,
            notes: a.notes || null,
            state: a.uf || 'RS',
            status: 'ACTIVE',
            federationStatus: 'ACTIVE',
          },
        })
      })
    )
    stats.athletes += batch.length
  }

  // 5. Create coaches
  for (const c of COACHES_DATA) {
    try {
      const teamId = findTeamByClubName(c.club)
      if (!teamId) {
        stats.skipped++
        stats.errors.push(`Coach ${c.n}: team not found for club "${c.club}"`)
        continue
      }
      await prisma.$executeRawUnsafe(
        `INSERT INTO "CoachStaff" ("id","teamId","name","role","email","phone","situation","isActive","createdAt","updatedAt") VALUES (?,?,?,?,?,?,?,?,?,?)`,
        randomUUID(), teamId, c.n, c.role, c.email || null, c.phone || null, 'ACTIVE', 1, now, now
      )
      stats.coaches++
    } catch (e: any) {
      stats.errors.push(`Coach ${c.n}: ${e.message}`)
    }
  }

  return NextResponse.json({
    success: true,
    message: `Importação concluída: ${stats.teams} times, ${stats.athletes} atletas, ${stats.coaches} treinadores`,
    stats,
  })
}